import React, { useState, useRef, useEffect } from 'react';
import { SERVICES } from '../constants';
import { ArrowUpRight, ChevronLeft, ChevronRight } from 'lucide-react';

const Services: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const scrollRef = useRef<HTMLDivElement>(null);
  const visibleCards = 3; // Number of cards visible on desktop

  const nextSlide = () => {
    if (currentIndex < SERVICES.length - visibleCards) {
      setCurrentIndex(prev => prev + 1);
    }
  };

  const prevSlide = () => {
    if (currentIndex > 0) {
      setCurrentIndex(prev => prev - 1);
    }
  };

  // Progress percentage for the bar
  const progress = ((currentIndex + visibleCards) / SERVICES.length) * 100;

  useEffect(() => {
    if (scrollRef.current) {
      const cardWidth = scrollRef.current.offsetWidth / visibleCards;
      scrollRef.current.scrollTo({
        left: currentIndex * cardWidth,
        behavior: 'smooth'
      });
    }
  }, [currentIndex]);

  return (
    <section className="py-24 bg-white overflow-hidden">
      <div className="container mx-auto px-6">
        {/* Header Section */}
        <div className="text-center max-w-4xl mx-auto mb-16">
          <h2 className="text-3xl md:text-5xl font-extrabold text-navy leading-tight">
            Welcome To Logistics. Master Your Global <br />
            <span className="text-steelBlue">Supply Chain with Expert Logistics</span>
          </h2>
        </div>

        {/* Slider Container */}
        <div className="relative mb-16">
          <div 
            ref={scrollRef}
            className="flex gap-6 overflow-x-hidden no-scrollbar pb-8"
          >
            {SERVICES.map((service, idx) => (
              <div 
                key={idx} 
                className="flex-shrink-0 w-full md:w-[calc(33.333%-16px)] group cursor-pointer"
              >
                <div className="relative aspect-[4/5] rounded-3xl overflow-hidden shadow-2xl transition-transform duration-500 group-hover:scale-[1.02]">
                  {/* Background Image */}
                  <img 
                    src={service.image} 
                    alt={service.title} 
                    className="absolute inset-0 w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
                  />

                  {/* Gradient Overlay */}
                  <div className="absolute inset-0 bg-gradient-to-t from-navy/90 via-navy/20 to-transparent"></div>

                  {/* Floating Action Button */}
                  <div className="absolute top-6 right-6">
                    <div className="w-12 h-12 bg-logisticsOrange rounded-full flex items-center justify-center text-white shadow-lg transition-transform duration-300 group-hover:rotate-45 group-hover:scale-110">
                      <ArrowUpRight className="w-6 h-6" />
                    </div>
                  </div>

                  {/* Text Content */}
                  <div className="absolute bottom-10 left-8 right-8">
                    <h3 className="text-2xl font-bold text-white leading-tight">
                      {service.title}
                    </h3>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* Navigation Controls */}
          <div className="flex items-center justify-between mt-12 px-2 max-w-6xl mx-auto">
            {/* Prev Button */}
            <button 
              onClick={prevSlide}
              disabled={currentIndex === 0}
              className={`w-14 h-14 rounded-full border border-gray-200 flex items-center justify-center transition-all ${
                currentIndex === 0 ? 'opacity-30 cursor-not-allowed' : 'hover:bg-navy hover:text-white hover:border-navy'
              }`}
            >
              <ChevronLeft className="w-6 h-6" />
            </button>

            {/* Progress Bar & Indicators */}
            <div className="flex-1 max-w-lg mx-12">
              <div className="relative h-1 bg-gray-100 rounded-full overflow-hidden">
                <div 
                  className="absolute top-0 left-0 h-full bg-logisticsOrange transition-all duration-500 rounded-full"
                  style={{ width: `${progress}%` }}
                ></div>
              </div>
              <div className="flex justify-center gap-2 mt-4">
                {Array.from({ length: Math.ceil(SERVICES.length / (visibleCards - 1)) }).map((_, i) => (
                   <div 
                    key={i} 
                    className={`w-2 h-2 rounded-full transition-all duration-300 ${
                      Math.floor(currentIndex / (visibleCards - 1)) === i ? 'bg-logisticsOrange w-4' : 'bg-gray-200'
                    }`}
                   />
                ))}
              </div>
            </div>

            {/* Next Button */}
            <button 
              onClick={nextSlide}
              disabled={currentIndex >= SERVICES.length - visibleCards}
              className={`w-14 h-14 rounded-full border border-gray-200 flex items-center justify-center transition-all ${
                currentIndex >= SERVICES.length - visibleCards ? 'opacity-30 cursor-not-allowed' : 'hover:bg-navy hover:text-white hover:border-navy'
              }`}
            >
              <ChevronRight className="w-6 h-6" />
            </button>
          </div>
        </div>

        {/* Symmetrical Bottom Label */}
        <div className="text-center">
            <span className="text-xs font-bold uppercase tracking-[0.3em] text-gray-400">
              Titan Freight Group Assurance
            </span>
        </div>
      </div>

      <style>{`
        .no-scrollbar::-webkit-scrollbar {
          display: none;
        }
        .no-scrollbar {
          -ms-overflow-style: none;
          scrollbar-width: none;
        }
      `}</style>
    </section>
  );
};

