import React, { useState, useRef, useEffect } from 'react';
import { SERVICES } from '../constants';
import { ArrowUpRight, ChevronLeft, ChevronRight } from 'lucide-react';

const Services: React.FC = () => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Responsive card visibility logic
  const [visibleCards, setVisibleCards] = useState(3);

  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth < 768) setVisibleCards(1);
      else if (window.innerWidth < 1024) setVisibleCards(2);
      else setVisibleCards(3);
    };
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const nextSlide = () => {
    if (currentIndex < SERVICES.length - visibleCards) {
      setCurrentIndex(prev => prev + 1);
    }
  };

  const prevSlide = () => {
    if (currentIndex > 0) {
      setCurrentIndex(prev => prev - 1);
    }
  };

  // Progress percentage for the bar
  const totalSteps = SERVICES.length - (visibleCards - 1);
  const progress = ((currentIndex + 1) / totalSteps) * 100;

  useEffect(() => {
    if (scrollRef.current) {
      const containerWidth = scrollRef.current.offsetWidth;
      const cardWidth = containerWidth / visibleCards;
      scrollRef.current.scrollTo({
        left: currentIndex * cardWidth,
        behavior: 'smooth'
      });
    }
  }, [currentIndex, visibleCards]);

  return (
    <section className="py-24 bg-white overflow-hidden selection:bg-logisticsOrange selection:text-white">
      <div className="container mx-auto px-6">

        {/* HEADER: Centered hero-style hierarchy */}
        <div className="text-center max-w-4xl mx-auto mb-20 space-y-4">
          <h2 className="text-3xl md:text-5xl lg:text-6xl font-extrabold text-navy leading-tight tracking-tight">
            Welcome To Logistics.
          </h2>
          <h3 className="text-xl md:text-3xl font-bold text-steelBlue opacity-90">
            Master Your Retail Supply Chain with Expert Logistics
          </h3>
        </div>

        {/* SLIDER: Card stack with visual focus */}
        <div className="relative max-w-7xl mx-auto">
          <div 
            ref={scrollRef}
            className="flex gap-6 overflow-x-hidden no-scrollbar pb-10 px-2"
          >
            {SERVICES.map((service, idx) => (
              <div 
                key={idx} 
                className="flex-shrink-0 w-full md:w-[calc(50%-12px)] lg:w-[calc(33.333%-16px)] group"
              >
                <div className="relative aspect-[4/5] rounded-[2.5rem] overflow-hidden shadow-2xl transition-all duration-700 hover:shadow-[0_20px_50px_rgba(11,42,74,0.3)]">
                  {/* High-Quality Image Background */}
                  <img 
                    src={service.image} 
                    alt={service.title} 
                    className="absolute inset-0 w-full h-full object-cover transition-transform duration-1000 group-hover:scale-110"
                  />

                  {/* Dark Gradient Overlay for Typography Legibility */}
                  <div className="absolute inset-0 bg-gradient-to-t from-navy/90 via-navy/40 to-transparent opacity-80 transition-opacity duration-500 group-hover:opacity-100"></div>

                  {/* Floating Action Button (Top Right) */}
                  <div className="absolute top-8 right-8 z-20">
                    <button className="w-14 h-14 bg-logisticsOrange rounded-full flex items-center justify-center text-white shadow-xl transition-all duration-500 hover:scale-110 active:scale-95 group-hover:rotate-12">
                      <ArrowUpRight className="w-7 h-7" />
                    </button>
                  </div>

                  {/* Overlaid Typography (Bottom) */}
                  <div className="absolute bottom-12 left-10 right-10 z-10">
                    <h4 className="text-2xl md:text-3xl font-bold text-white leading-tight drop-shadow-lg">
                      {service.title}
                    </h4>
                  </div>
                </div>
              </div>
            ))}
          </div>

          {/* NAVIGATION CONTROLS: Arrow buttons, progress bar, symmetrical layout */}
          <div className="flex items-center justify-center mt-12 gap-8">
            {/* Prev Button */}
            <button 
              onClick={prevSlide}
              disabled={currentIndex === 0}
              aria-label="Previous slide"
              className={`w-14 h-14 rounded-full border border-gray-100 flex items-center justify-center transition-all shadow-sm bg-white ${
                currentIndex === 0 ? 'opacity-30 cursor-not-allowed scale-90' : 'hover:bg-navy hover:text-white hover:border-navy hover:shadow-lg'
              }`}
            >
              <ChevronLeft className="w-6 h-6" />
            </button>

            {/* Centered Progress Bar */}
            <div className="w-64 md:w-96">
              <div className="relative h-1.5 bg-gray-100 rounded-full overflow-hidden">
                <div 
                  className="absolute top-0 left-0 h-full bg-logisticsOrange transition-all duration-700 ease-out rounded-full"
                  style={{ width: `${progress}%` }}
                ></div>
              </div>

              {/* Pagination Indicators (Symmetrical dots) */}
              <div className="flex justify-center gap-3 mt-6">
                {Array.from({ length: totalSteps }).map((_, i) => (
                   <button
                    key={i} 
                    onClick={() => setCurrentIndex(i)}
                    className={`h-2 rounded-full transition-all duration-500 ${
                      currentIndex === i ? 'bg-logisticsOrange w-8' : 'bg-gray-200 w-2 hover:bg-gray-300'
                    }`}
                   />
                ))}
              </div>
            </div>

            {/* Next Button */}
            <button 
              onClick={nextSlide}
              disabled={currentIndex >= SERVICES.length - visibleCards}
              aria-label="Next slide"
              className={`w-14 h-14 rounded-full border border-gray-100 flex items-center justify-center transition-all shadow-sm bg-white ${
                currentIndex >= SERVICES.length - visibleCards ? 'opacity-30 cursor-not-allowed scale-90' : 'hover:bg-navy hover:text-white hover:border-navy hover:shadow-lg'
              }`}
            >
              <ChevronRight className="w-6 h-6" />
            </button>
          </div>
        </div>

        {/* Branding Slogan */}
        <div className="text-center mt-20 opacity-30">
            <span className="text-[10px] md:text-xs font-bold uppercase tracking-[0.5em] text-navy">
              Ecosystem Coordination • Titan Freight Group
            </span>
        </div>
      </div>

      <style>{`
        .no-scrollbar::-webkit-scrollbar {
          display: none;
        }
        .no-scrollbar {
          -ms-overflow-style: none;
          scrollbar-width: none;
        }
      `}</style>
    </section>
  );
};

