const Testimonials: React.FC = () => {
  const [activeSlide, setActiveSlide] = useState(0);
  const [cardsPerPage, setCardsPerPage] = useState(2);

  // Responsive logic to decide how many cards to skip or show
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth < 768) setCardsPerPage(1);
      else setCardsPerPage(2);
    };
    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  const totalPages = Math.ceil(TESTIMONIALS.length / cardsPerPage);

  return (
    <section className="relative py-24 bg-[#051426] text-white overflow-hidden">
      {/* Decorative Diagonal Borders (Top) */}
      <div className="absolute top-0 left-0 w-full h-4 bg-navy opacity-20" style={{ backgroundImage: 'repeating-linear-gradient(45deg, transparent, transparent 10px, rgba(255,255,255,0.1) 10px, rgba(255,255,255,0.1) 20px)' }}></div>

      <div className="container mx-auto px-6 relative z-10">
        {/* Header: Centered with Dash Tagline */}
        <div className="text-center mb-16">
          <div className="flex items-center justify-center gap-2 mb-4">
            <div className="w-6 h-0.5 bg-logisticsOrange"></div>
            <span className="text-gray-400 font-medium tracking-widest text-sm uppercase">Testimonials</span>
          </div>
          <h2 className="text-4xl md:text-5xl font-extrabold leading-tight">
            Experience Shared by <br />
            <span className="text-logisticsOrange">Our Clients</span>
          </h2>
        </div>

        {/* Sliding Window Container */}
        <div className="relative max-w-6xl mx-auto overflow-hidden">
          <div 
            className="flex transition-transform duration-700 ease-in-out"
            style={{ transform: `translateX(-${activeSlide * (100 / (cardsPerPage === 1 ? 1 : 1)) }%)` }}
          >
            {/* We map all testimonials here. In a real world-class slider we might use a grid or flex gap */}
            <div className="flex gap-8 w-full">
              {/* Dynamic Grid Rendering based on active page */}
              <div className="grid md:grid-cols-2 gap-8 w-full flex-shrink-0">
                {TESTIMONIALS.slice(activeSlide * cardsPerPage, activeSlide * cardsPerPage + cardsPerPage).map((t, idx) => (
                  <div 
                    key={idx} 
                    className="bg-[#0B2A4A]/40 backdrop-blur-md p-10 rounded-[2rem] border border-white/5 transition-all duration-500 hover:bg-[#0B2A4A]/60 animate-in fade-in slide-in-from-bottom-4"
                  >
                    {/* Rating Section */}
                    <div className="flex items-center gap-1 mb-6">
                      {[...Array(5)].map((_, i) => (
                        <Star key={i} className="w-4 h-4 fill-logisticsOrange text-logisticsOrange" />
                      ))}
                      <span className="ml-2 text-sm font-bold text-gray-300">5.0</span>
                    </div>

                    {/* Title & Quote */}
                    <h3 className="text-xl font-bold mb-4 text-white">
                      {t.title || "Exceptional Service!"}
                    </h3>
                    <p className="text-gray-400 leading-relaxed mb-10 min-h-[100px]">
                      {t.quote}
                    </p>

                    {/* Profile Section */}
                    <div className="flex items-center gap-4">
                      <div className="w-14 h-14 rounded-full overflow-hidden border-2 border-steelBlue/30 shadow-lg">
                        <img 
                          src={t.avatar} 
                          alt={t.author} 
                          className="w-full h-full object-cover"
                        />
                      </div>
                      <div>
                        <p className="font-bold text-lg text-white">{t.author}</p>
                        <p className="text-sm text-gray-500 font-medium">{t.position}, {t.company}</p>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>

        {/* Navigation: Horizontal Pills */}
        <div className="flex justify-center items-center gap-3 mt-16">
          {[...Array(totalPages)].map((_, i) => (
            <button
              key={i}
              onClick={() => setActiveSlide(i)}
              className={`h-2 transition-all duration-500 rounded-full ${
                activeSlide === i 
                  ? 'bg-logisticsOrange w-10 shadow-[0_0_15px_rgba(243,112,33,0.5)]' 
                  : 'bg-white/10 w-4 hover:bg-white/20'
              }`}
              aria-label={`Go to page ${i + 1}`}
            />
          ))}
        </div>
      </div>

      {/* Decorative Diagonal Borders (Bottom) */}
      <div className="absolute bottom-0 left-0 w-full h-4 bg-navy opacity-20" style={{ backgroundImage: 'repeating-linear-gradient(45deg, transparent, transparent 10px, rgba(255,255,255,0.1) 10px, rgba(255,255,255,0.1) 20px)' }}></div>
    </section>
  );
};

