import React, { useState, useEffect } from 'react';
import { Menu, X } from 'lucide-react';
import { LOGO_URL } from '../constants';

const Header: React.FC = () => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navLinks = [
    { name: 'Home', href: '#home' },
    { name: 'About Us', href: '#about' },
    { name: 'Services', href: '#services' },
    { name: 'Testimonials', href: '#testimonials' },
    { name: 'Contact', href: '#contact' },
  ];

  const scrollToSection = (id: string) => {
    const element = document.querySelector(id);
    if (element) {
      element.scrollIntoView({ behavior: 'smooth' });
      setMobileMenuOpen(false);
    }
  };

  return (
    <header 
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
        isScrolled ? 'bg-white shadow-md py-3' : 'bg-transparent py-6'
      }`}
    >
      <div className="container mx-auto px-6 flex items-center justify-between">
        {/* Left Side: Logo */}
        <div className="flex-1">
          <a href="#home" className="flex items-center w-fit">
            <img src={LOGO_URL} alt="TFG Logo" className="h-10 md:h-12 w-auto object-contain" />
          </a>
        </div>

        {/* Center: Desktop Nav Links */}
        <nav className="hidden lg:flex items-center justify-center space-x-10 flex-grow">
          {navLinks.map((link) => (
            <button
              key={link.name}
              onClick={() => scrollToSection(link.href)}
              className={`text-sm font-bold transition-all uppercase tracking-[0.15em] border-b-2 border-transparent hover:border-logisticsOrange pb-1 ${
                isScrolled ? 'text-navy hover:text-logisticsOrange' : 'text-white hover:text-logisticsOrange'
              }`}
            >
              {link.name}
            </button>
          ))}
        </nav>

        {/* Right Side: Primary CTA */}
        <div className="hidden lg:flex items-center justify-end flex-1">
          <button 
            onClick={() => scrollToSection('#contact')}
            className="bg-logisticsOrange hover:bg-orange-600 text-white px-8 py-3 rounded-full text-xs font-black uppercase tracking-widest transition-all shadow-lg active:scale-95"
          >
            Get a Quote
          </button>
        </div>

        {/* Mobile Menu Toggle */}
        <button 
          className="lg:hidden text-current p-2"
          onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
        >
          {mobileMenuOpen ? (
            <X className={isScrolled ? 'text-navy' : 'text-white'} />
          ) : (
            <Menu className={isScrolled ? 'text-navy' : 'text-white'} />
          )}
        </button>
      </div>

      {/* Mobile Menu Overlay */}
      {mobileMenuOpen && (
        <div className="lg:hidden fixed inset-0 bg-navy z-40 flex flex-col items-center justify-center space-y-8 animate-in fade-in zoom-in duration-300">
          {navLinks.map((link) => (
            <button
              key={link.name}
              onClick={() => scrollToSection(link.href)}
              className="text-white text-3xl font-black uppercase tracking-widest hover:text-logisticsOrange transition-colors"
            >
              {link.name}
            </button>
          ))}
          <button 
            onClick={() => scrollToSection('#contact')}
            className="bg-logisticsOrange text-white px-12 py-5 rounded-full text-xl font-black uppercase tracking-widest mt-4 shadow-2xl"
          >
            Get a Quote
          </button>
          <button 
            onClick={() => setMobileMenuOpen(false)}
            className="absolute top-8 right-8 text-white/50 hover:text-white"
          >
            <X size={40} />
          </button>
        </div>
      )}
    </header>
  );
};

